 96→    override fun initData() {
 97→        super.initData()
 98→
 99→        if (intent != null) {
100→            mData = if (intent.hasExtra(KEY_REGISTER_DATA)) Gson().fromJson(
101→                intent.getStringExtra(KEY_REGISTER_DATA),
102→                RegisterData::class.java
103→            ) else RegisterData()
104→        }
105→
106→        mViewModel.init(this)
107→        mViewModel.progressDialogObservable.observe(this) { isShow ->
108→            if (isShow) showLoadingDialog() else dismissLoadingDialog()
109→        }
110→
111→        mViewModel.selectedRegion.observe(this) { region ->
112→            if (region != null) {
113→                checkRegion(region)
114→                checkIsEnableRegisterBtn()
115→            }
116→        }
117→
118→        mViewModel.selectedCurrency.observe(this) { currency ->
119→            if (currency != null) {
120→                checkIsEnableRegisterBtn()
121→            }
122→        }
123→
124→        mViewModel.legalAge.observe(this) { legalAge ->
125→            updateTermAge(legalAge)
126→        }
127→
128→        mViewModel.registerResponseStatus.observe(this) { responseStatus ->
129→            when (responseStatus) {
130→                RegisterRepository.Companion.RegisterReturnStatus.USERNAME_EXIST -> {
131→                    binding.scrollView.smoothScrollTo(0, 0)
132→                    binding.usernameLayout.error = getString(UiStr.HELPJOINUSUSERIDEXIST)
133→                }
134→
135→                RegisterRepository.Companion.RegisterReturnStatus.EMAIL_EXIST -> {
136→                    binding.scrollView.smoothScrollTo(0, 0)
137→                    binding.emailLayout.error = getString(UiStr.MSGJOINUSEMAILEXISTED)
138→                }
139→
140→                RegisterRepository.Companion.RegisterReturnStatus.EMAIL_USERNAME_EXIST -> {
141→                    binding.scrollView.smoothScrollTo(0, 0)
142→                    binding.emailLayout.error = getString(UiStr.MSGJOINUSEMAILEXISTED)
143→                    binding.usernameLayout.error = getString(UiStr.HELPJOINUSUSERIDEXIST)
144→                }
145→
146→                RegisterRepository.Companion.RegisterReturnStatus.FAIL -> {
147→                    DialogUtil.showSimpleDialog(
148→                        this,
149→                        getString(UiStr.TXTJOINUSSIGNUP),
150→                        getString(UiStr.MSGJOINUSFAIL),
151→                        getString(UiStr.TXTBTNCOMOK),
152→                        0
153→                    )
154→                }
155→
156→                RegisterRepository.Companion.RegisterReturnStatus.USERNAME_SAME_AS_PASSWORD -> {
157→                    DialogUtil.showSimpleDialog(
158→                        this,
159→                        getString(UiStr.TXTJOINUSSIGNUP),
160→                        getString(UiStr.USERNAMEANDPASSWORDSAMEERROR),
161→                        getString(UiStr.TXTBTNCOMOK),
162→                        0
163→                    )
164→                }
165→
166→                else -> {}
167→            }
168→
169→            if (responseStatus != RegisterRepository.Companion.RegisterReturnStatus.SUBMIT_SUCCESS) {
170→                checkIsEnableRegisterBtn()
171→
172→                binding.viewCaptchaLayout.captchaView.refreshCodeView()
173→                binding.viewCaptchaLayout.captcha.setText("")
174→            }
175→        }
176→
177→        mViewModel.isRegisterLoginSuccess.observe(this) { isSuccess ->
178→            if (isSuccess) {
179→                openUpLockPatternSetting()
180→            } else {
181→                DialogUtil.showSimpleDialog(
182→                    this,
183→                    getString(UiStr.TXTJOINUSSIGNUP),
184→                    getString(UiStr.MSGJOINUSFAIL),
185→                    getString(UiStr.TXTBTNCOMOK),
186→                    0
187→                )
188→            }
189→        }
190→        binding.vm = mViewModel
191→    }
