193→    override fun initView() {
194→        super.initView()
195→        getHeaderLoginBtn()!!.visibility = View.VISIBLE
196→        getHeaderLoginBtn()!!.setOnClickListener { mViewModel.onLoginClick(getHeaderLoginBtn() as View) }
197→
198→        binding.constraintLayout.setOnClickListener { binding.scrollView.clearFocus() }  //for force check affId
199→
