201→        binding.email.disableCopyPaste()
202→        binding.username.disableCopyPaste()
203→        binding.pwd.disableCopyPaste()
204→        binding.viewCaptchaLayout.captcha.disableCopyPaste()
205→
206→        //set init data before set click listener
207→        if (!TextUtils.isEmpty(mData.email)) binding.email.setText(mData.email, false)
208→
209→        binding.email.addTextChangedListener(object : TextWatcher {
210→            override fun beforeTextChanged(s: CharSequence, start: Int, count: Int, after: Int) {
211→                binding.emailLayout.error = ""
212→            }
213→
214→            override fun onTextChanged(s: CharSequence, start: Int, before: Int, count: Int) {}
215→            override fun afterTextChanged(editable: Editable) {
216→                isEmailEdited = true
217→                val inputStr = editable.toString().trim()
218→                if (!CommonUtils.isEmailFormatValid(inputStr)) {
219→                    binding.emailLayout.error = getString(UiStr.TIPJOINUSVALIDEMAIL)
220→                }
221→
222→                checkIsEnableRegisterBtn()
223→            }
224→        })
225→
